'\''2i /* the length of the first xlw columns of s, s is len bytes long */
static int lbuf_lwcut(char *s, int len)
{
	int i = 0, cpos = 0;
	while (i < len) {
		char *c = s + i;
		int wid = ren_cwid(c, cpos);
		if (cpos + wid > xlw && i)	/* i: always make progress */
			return i;
		cpos += wid;
		i += uc_len(c);
	}
	return len;
}

